class FlattenedDataset(Dataset):
    def __init__(self, subset, pixel_permutation=None):
        self.subset = subset
        self.pixel_permutation = pixel_permutation

    def __len__(self):
        return len(self.subset)

    def __getitem__(self, idx):
        image, label = self.subset[idx]   # image shape: [3,32,32]
        x = image.view(-1)                # shape: [3072]

        if self.pixel_permutation is not None:
            x = x[self.pixel_permutation]

        return x, label

