def show_misclassified_images(model, loader, num_images=10):
    model.eval()
    misclassified = []

    with torch.no_grad():
        for inputs, labels in loader:
            inputs, labels = inputs.to(device), labels.to(device)
            outputs = model(inputs)
            preds = torch.argmax(outputs, dim=1)

            for i in range(inputs.size(0)):
                if preds[i] != labels[i]:
                    misclassified.append((
                        inputs[i].cpu(),
                        labels[i].cpu().item(),
                        preds[i].cpu().item()
                    ))
                if len(misclassified) >= num_images:
                    break
            if len(misclassified) >= num_images:
                break

    plt.figure(figsize=(15, 6))
    for i, (flat_img, true_label, pred_label) in enumerate(misclassified):
        img = flat_img.view(3, 32, 32)
        img = img / 2 + 0.5  # unnormalize
        npimg = img.numpy()

        plt.subplot(2, 5, i + 1)
        plt.imshow(np.transpose(npimg, (1, 2, 0)))
        plt.title(f"T: {classes[true_label]}\nP: {classes[pred_label]}")
        plt.axis('off')

    plt.suptitle("Misclassified Test Images")
    plt.tight_layout()
    plt.show()

