def get_feature_maps(model, image_tensor):
    model.eval()

    feature_maps = {}

    with torch.no_grad():
        x = image_tensor.unsqueeze(0).to(device)

        x1 = F.relu(model.conv1(x))
        feature_maps["conv1"] = x1.cpu()

        x2 = model.pool(x1)
        x2 = F.relu(model.conv2(x2))
        feature_maps["conv2"] = x2.cpu()

        x3 = model.pool(x2)
        x3 = F.relu(model.conv3(x3))
        feature_maps["conv3"] = x3.cpu()

    return feature_maps

