class ShiftedDataset(Dataset):
    def __init__(self, base_dataset, shift_x=2, shift_y=2, flatten=False, pixel_permutation=None):
        self.base_dataset = base_dataset
        self.shift_x = shift_x
        self.shift_y = shift_y
        self.flatten = flatten
        self.pixel_permutation = pixel_permutation

    def __len__(self):
        return len(self.base_dataset)

    def __getitem__(self, idx):
        image, label = self.base_dataset[idx]   # [3,32,32]

        shifted = torch.roll(image, shifts=(self.shift_y, self.shift_x), dims=(1, 2))

        if self.flatten:
            shifted = shifted.view(-1)
            if self.pixel_permutation is not None:
                shifted = shifted[self.pixel_permutation]

        return shifted, label

# shifted data for CNN
